// BrightPath English, K-12 reading, grammar, vocabulary with real-life flavor
const { pick, shuffle, textChoices, q } = require('./helpers');

// Helper for bank-based skills
const _hasEmoji = s => /\p{Extended_Pictographic}/u.test(String(s));
// If only the correct answer carries an emoji, it visually stands out among plain-text
// distractors and gives itself away. Strip it so every choice looks the same.
function _balanceAnswer(a, w) {
  if (_hasEmoji(a) && !w.some(_hasEmoji)) return String(a).replace(/[\p{Extended_Pictographic}\u{FE0F}\u{200D}]/gu, '').replace(/\s{2,}/g, ' ').trim();
  return a;
}
function fromBank(bank) {
  return function () {
    const item = pick(bank);
    const a = _balanceAnswer(item.a, item.w);
    return q({
      prompt: item.p,
      choices: textChoices(a, item.w),
      answer: a,
      hint: item.h || '',
      explain: item.e || '',
      voice: item.v || (item.pg ? item.pg + ' … ' + item.p : item.p),
      passage: item.pg || null
    });
  };
}

